import java.util.*;

public int minPartitionDifference(int[] nums) {
    int n = nums.length / 2;
    Arrays.sort(nums);
    int firstSum = 0, secondSum = 0;
    for (int i = nums.length - 1; i >= 0; i--) {
        if (i % 2 == 0) {
            firstSum += nums[i];
        } else {
            secondSum += nums[i];
        }
    }
    return Math.abs(firstSum - secondSum);
}
```

